import logo from './logo.svg';
import './App.css';
import "./fonts/icomoon/style.css";
import "./css/bootstrap.min.css";
import "./css/jquery-ui.css";
import "./css/owl.carousel.min.css";
import "./css/owl.theme.default.min.css";
import "./css/jquery.fancybox.min.css";
import "./css/bootstrap-datepicker.css";
import "./fonts/flaticon/font/flaticon.css";
import "./css/aos.css";
import "./css/jquery.mb.YTPlayer.min.css";
import Header from "./components/header";
import Footer from "./components/footer";

function App() {
  return (
    <div class="site-section mb-5 mt-5" id="call-to-action">
  <div class="container">
      <div class="row justify-content-center">
          <div class="col-lg-7">
              <h3 class="section-title">Customer Service</h3>
              <p style="color:black">For detail information related to the promo, please contact us by telephone +6012345678900.</p>
          </div>
          <div class="col-lg-3 text-center">
              <a class="cta-btn" style="vertical-align: middle!important;" href="tel:+6012345678900" target="_blank"><i class="icon-phone" aria-hidden="true"></i></a>
          </div>
      </div>
  </div>
</div>
  );
}

export default App;
